/**
 * Configuration for the IframeManager
 */
export interface IframeManagerConfig {
  /** URL to load in the iframe */
  src: string;

  /** Z-index for the overlay */
  zIndex: number;

  /** Callback when iframe loads */
  onLoad?: () => void;

  /** Callback when iframe fails to load */
  onError?: (error: Error) => void;
}

/**
 * Manages the iframe DOM element and modal overlay
 */
export class IframeManager {
  private config: IframeManagerConfig;
  private overlay: HTMLDivElement | null = null;
  private iframe: HTMLIFrameElement | null = null;
  private isVisible = false;

  constructor(config: IframeManagerConfig) {
    this.config = config;
  }

  /**
   * Creates the iframe and overlay elements (hidden by default)
   */
  create(): HTMLIFrameElement {
    if (this.iframe) {
      return this.iframe;
    }

    // Create overlay container
    this.overlay = document.createElement('div');
    this.overlay.setAttribute('data-dam-picker-overlay', 'true');
    this.applyOverlayStyles(this.overlay);

    // Create modal container
    const modal = document.createElement('div');
    this.applyModalStyles(modal);

    // Create iframe
    this.iframe = document.createElement('iframe');
    this.iframe.setAttribute('data-dam-picker-iframe', 'true');
    this.iframe.src = this.config.src;
    this.iframe.allow = 'clipboard-write';
    this.applyIframeStyles(this.iframe);

    // Set up load/error handlers
    this.iframe.onload = () => {
      this.config.onLoad?.();
    };

    this.iframe.onerror = () => {
      this.config.onError?.(new Error('Failed to load picker iframe'));
    };

    // Handle overlay click (close on backdrop click)
    this.overlay.addEventListener('click', (e) => {
      if (e.target === this.overlay) {
        // Dispatch custom event that the DamPicker can listen for
        this.overlay?.dispatchEvent(new CustomEvent('backdropclick'));
      }
    });

    // Handle escape key
    const handleKeydown = (e: KeyboardEvent) => {
      if (e.key === 'Escape' && this.isVisible) {
        this.overlay?.dispatchEvent(new CustomEvent('escapekey'));
      }
    };
    document.addEventListener('keydown', handleKeydown);

    // Store keydown handler for cleanup
    (this.overlay as HTMLDivElement & { _keydownHandler?: (e: KeyboardEvent) => void })._keydownHandler =
      handleKeydown;

    // Assemble DOM structure
    modal.appendChild(this.iframe);
    this.overlay.appendChild(modal);
    document.body.appendChild(this.overlay);

    return this.iframe;
  }

  /**
   * Shows the overlay and iframe
   */
  show(): void {
    if (!this.overlay) {
      this.create();
    }

    if (this.overlay) {
      this.overlay.style.display = 'flex';
      this.overlay.style.opacity = '0';
      // Trigger reflow for animation
      void this.overlay.offsetHeight;
      this.overlay.style.opacity = '1';
      this.isVisible = true;

      // Prevent body scroll
      document.body.style.overflow = 'hidden';
    }
  }

  /**
   * Hides the overlay and iframe
   */
  hide(): void {
    if (this.overlay) {
      this.overlay.style.opacity = '0';
      // Wait for fade out animation
      setTimeout(() => {
        if (this.overlay) {
          this.overlay.style.display = 'none';
        }
      }, 200);
      this.isVisible = false;

      // Restore body scroll
      document.body.style.overflow = '';
    }
  }

  /**
   * Destroys the iframe and overlay, removing them from the DOM
   */
  destroy(): void {
    if (this.overlay) {
      // Remove keydown listener
      const handler = (this.overlay as HTMLDivElement & { _keydownHandler?: (e: KeyboardEvent) => void })
        ._keydownHandler;
      if (handler) {
        document.removeEventListener('keydown', handler);
      }

      // Remove from DOM
      this.overlay.remove();
      this.overlay = null;
    }

    this.iframe = null;
    this.isVisible = false;

    // Restore body scroll
    document.body.style.overflow = '';
  }

  /**
   * Returns the iframe element
   */
  getIframe(): HTMLIFrameElement | null {
    return this.iframe;
  }

  /**
   * Returns the overlay element
   */
  getOverlay(): HTMLDivElement | null {
    return this.overlay;
  }

  /**
   * Returns whether the picker is currently visible
   */
  getIsVisible(): boolean {
    return this.isVisible;
  }

  /**
   * Applies styles to the overlay element
   */
  private applyOverlayStyles(overlay: HTMLDivElement): void {
    Object.assign(overlay.style, {
      position: 'fixed',
      top: '0',
      left: '0',
      right: '0',
      bottom: '0',
      backgroundColor: 'rgba(0, 0, 0, 0.5)',
      backdropFilter: 'blur(4px)',
      display: 'none',
      alignItems: 'center',
      justifyContent: 'center',
      zIndex: String(this.config.zIndex),
      transition: 'opacity 0.2s ease-in-out',
      padding: '16px',
    });
  }

  /**
   * Applies styles to the modal container
   */
  private applyModalStyles(modal: HTMLDivElement): void {
    Object.assign(modal.style, {
      width: '100%',
      maxWidth: '1200px',
      height: '100%',
      maxHeight: '80vh',
      backgroundColor: 'white',
      borderRadius: '12px',
      boxShadow: '0 25px 50px -12px rgba(0, 0, 0, 0.25)',
      overflow: 'hidden',
      display: 'flex',
      flexDirection: 'column',
    });
  }

  /**
   * Applies styles to the iframe element
   */
  private applyIframeStyles(iframe: HTMLIFrameElement): void {
    Object.assign(iframe.style, {
      width: '100%',
      height: '100%',
      border: 'none',
      backgroundColor: 'white',
    });
  }
}
