import {
  MESSAGE_TYPES,
  isPickerMessage,
  type PickerMessage,
  type InitMessage,
  type CloseMessage,
  type DamPickerFilters,
  type SelectedAsset,
  type DamPickerError,
} from './types';

/**
 * Generates a random nonce for message validation
 */
export function generateNonce(): string {
  return Math.random().toString(36).substring(2) + Date.now().toString(36);
}

/**
 * Handles postMessage communication between SDK and picker iframe
 */
export class MessageBridge {
  private iframe: HTMLIFrameElement | null = null;
  private expectedOrigin: string;
  private nonce: string;
  private messageHandler: ((event: MessageEvent) => void) | null = null;

  // Callbacks
  private onReady?: () => void;
  private onSelect?: (asset: SelectedAsset) => void;
  private onCancel?: () => void;
  private onError?: (error: DamPickerError) => void;

  constructor(expectedOrigin: string) {
    this.expectedOrigin = expectedOrigin;
    this.nonce = generateNonce();
  }

  /**
   * Connects the bridge to an iframe and starts listening for messages
   */
  connect(
    iframe: HTMLIFrameElement,
    callbacks: {
      onReady?: () => void;
      onSelect?: (asset: SelectedAsset) => void;
      onCancel?: () => void;
      onError?: (error: DamPickerError) => void;
    }
  ): void {
    this.iframe = iframe;
    this.onReady = callbacks.onReady;
    this.onSelect = callbacks.onSelect;
    this.onCancel = callbacks.onCancel;
    this.onError = callbacks.onError;

    // Set up message listener
    this.messageHandler = this.handleMessage.bind(this);
    window.addEventListener('message', this.messageHandler);
  }

  /**
   * Disconnects the bridge and stops listening for messages
   */
  disconnect(): void {
    if (this.messageHandler) {
      window.removeEventListener('message', this.messageHandler);
      this.messageHandler = null;
    }
    this.iframe = null;
  }

  /**
   * Handles incoming postMessage events
   */
  private handleMessage(event: MessageEvent): void {
    // Ignore messages from browser extensions (React DevTools, etc.)
    if (event.data?.source?.startsWith('react-devtools')) {
      return;
    }

    // For READY message, we accept any origin since we don't know it yet
    // For other messages, validate the origin
    if (event.data?.type !== MESSAGE_TYPES.READY) {
      if (!this.validateOrigin(event.origin)) {
        return;
      }
    }

    // Validate message structure
    if (!isPickerMessage(event.data)) {
      return;
    }

    const message = event.data as PickerMessage;

    switch (message.type) {
      case MESSAGE_TYPES.READY:
        this.onReady?.();
        break;

      case MESSAGE_TYPES.SELECT:
        if (message.payload?.asset) {
          this.onSelect?.(message.payload.asset);
        }
        break;

      case MESSAGE_TYPES.CANCEL:
        this.onCancel?.();
        break;

      case MESSAGE_TYPES.ERROR:
        if (message.payload?.error) {
          this.onError?.(message.payload.error);
        }
        break;
    }
  }

  /**
   * Validates that the message origin matches expected origin
   */
  private validateOrigin(origin: string): boolean {
    // Allow localhost for development
    if (origin.includes('localhost') || origin.includes('127.0.0.1')) {
      return true;
    }

    // Extract hostname from expected origin for comparison
    try {
      const expectedUrl = new URL(this.expectedOrigin);
      const actualUrl = new URL(origin);
      return expectedUrl.hostname === actualUrl.hostname;
    } catch {
      return false;
    }
  }

  /**
   * Sends INIT message to the picker iframe
   */
  sendInit(token: string, filters?: DamPickerFilters): void {
    const message: InitMessage = {
      type: MESSAGE_TYPES.INIT,
      nonce: this.nonce,
      payload: {
        token,
        filters,
      },
    };
    this.postMessage(message);
  }

  /**
   * Sends CLOSE message to the picker iframe
   */
  sendClose(): void {
    const message: CloseMessage = {
      type: MESSAGE_TYPES.CLOSE,
      nonce: this.nonce,
    };
    this.postMessage(message);
  }

  /**
   * Posts a message to the iframe
   */
  private postMessage(message: PickerMessage): void {
    if (!this.iframe?.contentWindow) {
      console.warn('[DamPicker] Cannot send message: iframe not available');
      return;
    }

    this.iframe.contentWindow.postMessage(message, this.expectedOrigin);
  }
}
