/**
 * Configuration options for the DamPicker
 */
export interface DamPickerConfig {
  /** Fluid API token for authentication */
  token: string;

  /** Override the default picker app URL (defaults to https://admin.fluid.app/dam-picker) */
  baseUrl?: string;

  /** Z-index for the modal overlay (default: 10000) */
  zIndex?: number;

  /** Filter options for assets */
  filters?: DamPickerFilters;
}

/**
 * Filter options to narrow down displayed assets
 */
export interface DamPickerFilters {
  /** Filter by asset types */
  assetTypes?: AssetType[];
}

/**
 * Supported asset types
 */
export type AssetType = 'images' | 'videos' | 'documents' | 'audio';

/**
 * Callbacks for DamPicker events
 */
export interface DamPickerCallbacks {
  /** Called when user selects an asset */
  onSelect: (asset: SelectedAsset) => void;

  /** Called when user cancels/closes the picker */
  onCancel?: () => void;

  /** Called when an error occurs */
  onError?: (error: DamPickerError) => void;

  /** Called when the picker is ready to use */
  onReady?: () => void;
}

/**
 * Full configuration including callbacks
 */
export type DamPickerOptions = DamPickerConfig & DamPickerCallbacks;

/**
 * The asset object returned when user makes a selection
 */
export interface SelectedAsset {
  /** Public URL to access the asset */
  url: string;

  /** Unique asset identifier */
  assetCode: string;

  /** Display name of the asset */
  name: string;

  /** MIME type (e.g., "image/png", "video/mp4") */
  mimeType: string;

  /** Optional metadata about the asset */
  metadata?: AssetMetadata;

  /** ID of the selected variant (if applicable) */
  variantId?: string;
}

/**
 * Additional metadata about an asset
 */
export interface AssetMetadata {
  /** Width in pixels (for images/videos) */
  width?: number;

  /** Height in pixels (for images/videos) */
  height?: number;

  /** File size in bytes */
  fileSize?: number;
}

/**
 * Error object for picker failures
 */
export interface DamPickerError {
  /** Error code for programmatic handling */
  code: DamPickerErrorCode;

  /** Human-readable error message */
  message: string;
}

/**
 * Possible error codes
 */
export type DamPickerErrorCode =
  | 'AUTHENTICATION_ERROR'
  | 'NETWORK_ERROR'
  | 'TIMEOUT'
  | 'IFRAME_LOAD_ERROR'
  | 'UNKNOWN';

/**
 * Internal state of the picker
 */
export type DamPickerState = 'idle' | 'loading' | 'ready' | 'open' | 'closed';

// ============================================================================
// PostMessage Protocol Types
// ============================================================================

/**
 * Message types for postMessage communication between SDK and picker app
 */
export const MESSAGE_TYPES = {
  /** Picker app signals it's ready to receive configuration */
  READY: 'DAM_PICKER_READY',

  /** SDK sends initialization data (token, filters) */
  INIT: 'DAM_PICKER_INIT',

  /** Picker app sends selected asset back to SDK */
  SELECT: 'DAM_PICKER_SELECT',

  /** User cancelled the picker */
  CANCEL: 'DAM_PICKER_CANCEL',

  /** An error occurred in the picker */
  ERROR: 'DAM_PICKER_ERROR',

  /** SDK requests the picker to close */
  CLOSE: 'DAM_PICKER_CLOSE',
} as const;

export type MessageType = (typeof MESSAGE_TYPES)[keyof typeof MESSAGE_TYPES];

/**
 * Base message structure
 */
export interface BaseMessage {
  type: MessageType;
  nonce?: string;
}

/**
 * READY message - sent by picker when loaded
 */
export interface ReadyMessage extends BaseMessage {
  type: typeof MESSAGE_TYPES.READY;
  payload?: undefined;
}

/**
 * INIT message - sent by SDK to configure picker
 */
export interface InitMessage extends BaseMessage {
  type: typeof MESSAGE_TYPES.INIT;
  payload: {
    token: string;
    filters?: DamPickerFilters;
  };
}

/**
 * SELECT message - sent by picker when user selects asset
 */
export interface SelectMessage extends BaseMessage {
  type: typeof MESSAGE_TYPES.SELECT;
  payload: {
    asset: SelectedAsset;
  };
}

/**
 * CANCEL message - sent by picker when user cancels
 */
export interface CancelMessage extends BaseMessage {
  type: typeof MESSAGE_TYPES.CANCEL;
  payload?: undefined;
}

/**
 * ERROR message - sent by picker on errors
 */
export interface ErrorMessage extends BaseMessage {
  type: typeof MESSAGE_TYPES.ERROR;
  payload: {
    error: DamPickerError;
  };
}

/**
 * CLOSE message - sent by SDK to close picker
 */
export interface CloseMessage extends BaseMessage {
  type: typeof MESSAGE_TYPES.CLOSE;
  payload?: undefined;
}

/**
 * Union of all message types
 */
export type PickerMessage =
  | ReadyMessage
  | InitMessage
  | SelectMessage
  | CancelMessage
  | ErrorMessage
  | CloseMessage;

/**
 * Type guard to check if a message is a valid picker message
 */
export function isPickerMessage(data: unknown): data is PickerMessage {
  if (typeof data !== 'object' || data === null) return false;
  const msg = data as Record<string, unknown>;
  return typeof msg.type === 'string' && Object.values(MESSAGE_TYPES).includes(msg.type as MessageType);
}

/**
 * Default picker URL (hosted in fluid-admin)
 */
export const DEFAULT_PICKER_URL = 'https://admin.fluid.app/dam-picker';
