import { IframeManager } from './iframe-manager';
import { MessageBridge } from './message-bridge';
import {
  DEFAULT_PICKER_URL,
  type DamPickerOptions,
  type DamPickerState,
  type DamPickerError,
  type SelectedAsset,
} from './types';

/**
 * Default configuration values
 */
const DEFAULTS = {
  zIndex: 10000,
  loadTimeout: 10000, // 10 seconds
};

/**
 * Main DamPicker class - the primary API for embedding the DAM picker
 */
export class DamPicker {
  private options: DamPickerOptions;
  private iframeManager: IframeManager | null = null;
  private messageBridge: MessageBridge | null = null;
  private state: DamPickerState = 'idle';
  private loadTimeoutId: ReturnType<typeof setTimeout> | null = null;

  constructor(options: DamPickerOptions) {
    this.options = {
      zIndex: DEFAULTS.zIndex,
      ...options,
    };

    this.validateOptions();
  }

  /**
   * Opens the picker modal
   */
  open(): void {
    if (this.state === 'open' || this.state === 'loading') {
      console.warn('[DamPicker] Picker is already open or loading');
      return;
    }

    this.state = 'loading';

    // Get the picker URL
    const pickerUrl = this.getPickerUrl();

    // Create iframe manager
    this.iframeManager = new IframeManager({
      src: pickerUrl,
      zIndex: this.options.zIndex ?? DEFAULTS.zIndex,
      onLoad: () => {
        // Iframe loaded, but we wait for READY message before considering it ready
      },
      onError: (error) => {
        this.handleError({
          code: 'IFRAME_LOAD_ERROR',
          message: error.message,
        });
      },
    });

    // Create message bridge
    this.messageBridge = new MessageBridge(pickerUrl);

    // Create the iframe
    const iframe = this.iframeManager.create();

    // Connect message bridge
    this.messageBridge.connect(iframe, {
      onReady: () => this.handleReady(),
      onSelect: (asset) => this.handleSelect(asset),
      onCancel: () => this.handleCancel(),
      onError: (error) => this.handleError(error),
    });

    // Listen for backdrop/escape events
    const overlay = this.iframeManager.getOverlay();
    if (overlay) {
      overlay.addEventListener('backdropclick', () => this.handleCancel());
      overlay.addEventListener('escapekey', () => this.handleCancel());
    }

    // Show the overlay
    this.iframeManager.show();

    // Set load timeout
    this.loadTimeoutId = setTimeout(() => {
      if (this.state === 'loading') {
        this.handleError({
          code: 'TIMEOUT',
          message: 'Picker failed to load within timeout period',
        });
      }
    }, DEFAULTS.loadTimeout);
  }

  /**
   * Closes the picker modal
   */
  close(): void {
    this.clearLoadTimeout();

    // Send close message to iframe
    this.messageBridge?.sendClose();

    // Hide the overlay
    this.iframeManager?.hide();

    this.state = 'closed';
  }

  /**
   * Destroys the picker instance, cleaning up all resources
   */
  destroy(): void {
    this.clearLoadTimeout();

    // Disconnect message bridge
    this.messageBridge?.disconnect();
    this.messageBridge = null;

    // Destroy iframe and overlay
    this.iframeManager?.destroy();
    this.iframeManager = null;

    this.state = 'idle';
  }

  /**
   * Returns whether the picker is currently open
   */
  isOpen(): boolean {
    return this.state === 'open' || this.state === 'loading';
  }

  /**
   * Returns the current state of the picker
   */
  getState(): DamPickerState {
    return this.state;
  }

  /**
   * Handles the READY message from the picker iframe
   */
  private handleReady(): void {
    this.clearLoadTimeout();
    this.state = 'ready';

    // Send initialization data
    this.messageBridge?.sendInit(this.options.token, this.options.filters);

    this.state = 'open';
    this.options.onReady?.();
  }

  /**
   * Handles asset selection from the picker
   */
  private handleSelect(asset: SelectedAsset): void {
    this.close();
    this.options.onSelect(asset);
  }

  /**
   * Handles cancel/close from the picker
   */
  private handleCancel(): void {
    this.close();
    this.options.onCancel?.();
  }

  /**
   * Handles errors from the picker
   */
  private handleError(error: DamPickerError): void {
    this.close();
    this.options.onError?.(error);
  }

  /**
   * Gets the picker app URL based on configuration
   */
  private getPickerUrl(): string {
    return this.options.baseUrl ?? DEFAULT_PICKER_URL;
  }

  /**
   * Clears the load timeout if set
   */
  private clearLoadTimeout(): void {
    if (this.loadTimeoutId) {
      clearTimeout(this.loadTimeoutId);
      this.loadTimeoutId = null;
    }
  }

  /**
   * Validates the constructor options
   */
  private validateOptions(): void {
    if (!this.options.token) {
      throw new Error('[DamPicker] token is required');
    }

    if (typeof this.options.onSelect !== 'function') {
      throw new Error('[DamPicker] onSelect callback is required');
    }
  }
}
